
import { defineComponent, PropType } from 'vue';
import 'vue3-carousel/dist/carousel.css';
import { Carousel, Slide, Navigation } from 'vue3-carousel';

export default defineComponent({
	name: 'TheCarousel',
	components: {
		Carousel,
		Slide,
		Navigation,
	},
	props: {
		urls: {
			type: Object as PropType<Array<string>>,

		},
	},
	data: () => ({
		// carousel settings
		settings: {
			itemsToShow: 1,
			snapAlign: 'center',
			wrapAround: true,
		},
	}),
});
